func ProcessPayment(ctx context.Context, p *Payment) error {
    data, _ := json.Marshal(p)
    // Write to cache first, then async DB write
    rdb.Set(ctx, "payment:"+p.ID, data, 1*time.Hour)
    go func() {
        // fire-and-forget: no ACK, no retry, no durable queue
        _ = db.SavePayment(context.Background(), p)
    }()
    return nil // caller thinks payment is persisted
}
